package main

import (
    "crypto/rand"
    "crypto/rsa"
    "io"
)

// Compliant: Strong RSA key generation
func generateStrongRSAKey() (*rsa.PrivateKey, error) {
    // GOOD: 2048-bit minimum, 4096-bit recommended
    return rsa.GenerateKey(rand.Reader, 2048)
}

// GOOD: Cryptographically secure key generation
func generateSecureKey(keySize int) ([]byte, error) {
    // GOOD: Using crypto/rand for secure random generation
    key := make([]byte, keySize)
    _, err := io.ReadFull(rand.Reader, key)
    if err != nil {
        return nil, err
    }
    return key, nil
}

// GOOD: Generate AES-256 key
func generateAES256Key() ([]byte, error) {
    // GOOD: 256-bit key for AES-256
    return generateSecureKey(32)
}

package main

import (
    "crypto/aes"
    "crypto/cipher"
    "crypto/rand"
    "crypto/elliptic"
    "crypto/ecdsa"
    "io"
)

// Compliant: Strong symmetric encryption
func createStrongCipher() (cipher.AEAD, error) {
    // GOOD: AES-256 with GCM mode
    key := make([]byte, 32) // 256 bits
    if _, err := io.ReadFull(rand.Reader, key); err != nil {
        return nil, err
    }

    block, err := aes.NewCipher(key)
    if err != nil {
        return nil, err
    }

    // GOOD: GCM mode provides authentication
    return cipher.NewGCM(block)
}

// GOOD: Strong elliptic curve key generation
func generateECDSAKey() (*ecdsa.PrivateKey, error) {
    // GOOD: P-256 curve is secure and widely supported
    return ecdsa.GenerateKey(elliptic.P256(), rand.Reader)
}

// GOOD: Key derivation with proper parameters
func deriveKeyFromPassword(password, salt []byte) []byte {
    // In practice, use scrypt or Argon2 for password-based key derivation
    // This is a simplified example
    return pbkdf2.Key(password, salt, 100000, 32, sha256.New)
